// // This module reads data from a 4-bit input port based on a 2-bit address signal. It is triggered by a clock signal and includes an active-high reset functionality. When the reset_n signal is high, the output `readdata` is set to zero; otherwise, when the specified address is non-zero, the module outputs the data received from the input port (`in_port`). This effectively creates a mechanism to read input data conditionally based on the address provided, functioning as a basic interface for data transfer in a digital system.
module top_module(
                    // inputs:
                     address,
                     clk,
                     in_port,
                     reset_n,

                    // outputs:
                     readdata
                  )
;output  [  3: 0] readdata;
  input   [  1: 0] address;
  input            clk;
  input   [  3: 0] in_port;
  input            reset_n;

  wire             clk_en;
  wire    [  3: 0] data_in;
  wire    [  3: 0] read_mux_out;
  reg     [  3: 0] readdata;
  assign clk_en = 1;
  //s1, which is an e_avalon_slave
  assign read_mux_out = {4 {(address == 0)}} & data_in;
  always @(posedge clk or negedge reset_n)
    begin
      if (reset_n == 0)
          readdata <= 0;
      else if (clk_en)
          readdata <= read_mux_out;
    end


  assign data_in = in_port;

endmodule
